        return False
    present = set()
    for i in range(1, len(ops)):
        op, a, out = ops[i], arg_lists[i], outputs[i]
        if op == 'insert':
            expected = a[0] not in present
            present.add(a[0])
            if out != expected:
                return False
        elif op == 'remove':
            expected = a[0] in present
            present.discard(a[0])
            if out != expected:
                return False
        elif op == 'getRandom':
            if out not in present:
                return False
    return True

