function validate(args, outputs) {
  const [ops, argLists] = args;
  if (!Array.isArray(outputs) || outputs.length !== ops.length) return false;
  const present = new Set();
  for (let i = 1; i < ops.length; i++) {
    const op = ops[i], a = argLists[i], out = outputs[i];
    if (op === 'insert') {
      const expected = !present.has(a[0]);
      present.add(a[0]);
      if (out !== expected) return false;
    } else if (op === 'remove') {
      const expected = present.has(a[0]);
      present.delete(a[0]);
      if (out !== expected) return false;
    } else if (op === 'getRandom') {
      if (!present.has(out)) return false;
    }
  }
  return true;
}

