import random


class RandomizedSet:
    def __init__(self):
        self.items = []
        self.index = {}
    def insert(self, val):
        if val in self.index:
            return False
        self.index[val] = len(self.items)
        self.items.append(val)
        return True
    def remove(self, val):
        if val not in self.index:
            return False
        i = self.index.pop(val)
        last = self.items.pop()
        if i < len(self.items):
            self.items[i] = last
            self.index[last] = i
        return True
    def getRandom(self):
        return random.choice(self.items)

